import React, { useEffect, useRef } from 'react';

interface InkCanvasProps {
  darkMode?: boolean;
}

const InkCanvas: React.FC<InkCanvasProps> = ({ darkMode = false }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const darkModeRef = useRef(darkMode);

  useEffect(() => {
    darkModeRef.current = darkMode;
  }, [darkMode]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d', { alpha: true });
    if (!ctx) return;

    let width = window.innerWidth;
    let height = window.innerHeight;
    let animationFrameId: number;
    let time = 0;

    // --- Configuration ---
    const LAYERS = 4;

    // --- Classes ---

    class Mist {
      x: number;
      y: number;
      w: number;
      h: number;
      speed: number;
      opacity: number;

      constructor() {
        this.x = Math.random() * width;
        this.y = height * (0.6 + Math.random() * 0.4);
        this.w = width * (0.5 + Math.random());
        this.h = height * 0.2;
        this.speed = Math.random() * 0.2 + 0.05;
        this.opacity = Math.random() * 0.3;
      }

      update() {
        this.x -= this.speed;
        if (this.x + this.w < 0) {
          this.x = width;
        }
      }

      draw(ctx: CanvasRenderingContext2D, isNight: boolean) {
        const grad = ctx.createRadialGradient(
          this.x + this.w/2, this.y, 0,
          this.x + this.w/2, this.y, this.w/2
        );
        const baseColor = isNight ? '20, 20, 25' : '255, 255, 255';
        grad.addColorStop(0, `rgba(${baseColor}, ${this.opacity})`);
        grad.addColorStop(1, `rgba(${baseColor}, 0)`);

        ctx.fillStyle = grad;
        ctx.fillRect(this.x, this.y - this.h/2, this.w, this.h);
      }
    }

    class InkMountain {
      index: number;
      offset: number;
      speed: number;
      points: number[];

      constructor(index: number) {
        this.index = index;
        this.offset = Math.random() * 1000;
        // Far mountains move slower
        this.speed = 0.05 + ((LAYERS - index) * 0.05);
        this.points = [];
      }

      // Generate Perlin-ish noise for mountain shape
      getHeight(x: number) {
        const t = time * 0.002;
        // Parallax scrolling x
        const xOff = x * 0.002 + this.offset + (t * this.speed * 5);

        // Different frequencies for jaggedness vs rolling hills
        const scale = this.index === 0 ? 0.5 : 1.0; // Front layer rougher

        const y = 
          Math.sin(xOff) * 1.0 +
          Math.sin(xOff * 2.3) * 0.5 +
          Math.sin(xOff * 4.7) * 0.25;

        // Base height depends on layer index (Far = Higher/Smaller, Near = Lower/Bigger)
        const baseHeight = height * (0.6 + (this.index * 0.1));
        const amplitude = height * (0.15 - (this.index * 0.02));

        return baseHeight - (y * amplitude);
      }

      draw(ctx: CanvasRenderingContext2D, darkness: number) {
        // Calculate Ink Color (Shanshui Style)
        // Distance fog: Far mountains are lighter/grayer. Near are darker.
        // Index 0 = Back (Lightest), Index 3 = Front (Darkest)

        // Invert index for logic: 0 is closest, 3 is furthest in typical array, 
        // but let's say index 0 is furthest back.

        const depth = this.index / (LAYERS - 1); // 0.0 to 1.0

        // Day Colors
        const dayR = 40 + (depth * 20); // Dark gray to lighter gray
        const dayG = 45 + (depth * 20);
        const dayB = 50 + (depth * 25);
        const dayAlpha = 0.8 - (this.index * 0.15); // Front is darker/clearer

        // Night Colors (Cooler, Darker)
        const nightR = 10;
        const nightG = 15;
        const nightB = 25;
        const nightAlpha = 0.9 - (this.index * 0.1);

        const r = dayR + (nightR - dayR) * darkness;
        const g = dayG + (nightG - dayG) * darkness;
        const b = dayB + (nightB - dayB) * darkness;

        // Ink Wash Gradient Effect (Top transparent, bottom solid)
        const gradient = ctx.createLinearGradient(0, height * 0.3, 0, height);

        // Top of mountain (Peak)
        gradient.addColorStop(0, `rgba(${r}, ${g}, ${b}, ${0})`); 
        // Body of mountain
        gradient.addColorStop(0.5, `rgba(${r}, ${g}, ${b}, ${0.8})`); 
        // Bottom (Solid Ink)
        gradient.addColorStop(1, `rgba(${r}, ${g}, ${b}, 1)`);

        ctx.fillStyle = gradient;

        ctx.beginPath();

        // Start bottom left
        ctx.moveTo(0, height);

        // Trace mountain tops
        const step = 20; // Resolution
        for (let x = 0; x <= width + step; x += step) {
           const y = this.getHeight(x);
           ctx.lineTo(x, y);
        }

        // End bottom right
        ctx.lineTo(width, height);
        ctx.closePath();
        ctx.fill();
      }
    }

    // --- State ---
    const layers: InkMountain[] = [];
    const mists: Mist[] = [];

    const init = () => {
       layers.length = 0;
       // Create layers Back to Front
       for(let i=0; i<LAYERS; i++) {
         layers.push(new InkMountain(i));
       }
       mists.length = 0;
       for(let i=0; i<5; i++) {
         mists.push(new Mist());
       }
    };

    const resize = () => {
      width = window.innerWidth;
      height = window.innerHeight;
      const dpr = window.devicePixelRatio || 1;
      canvas.width = width * dpr;
      canvas.height = height * dpr;
      ctx.scale(dpr, dpr);
      init();
    };

    let currentDarkness = 0;

    const animate = () => {
      const targetDarkness = darkModeRef.current ? 1 : 0;
      currentDarkness += (targetDarkness - currentDarkness) * 0.05;

      ctx.clearRect(0, 0, width, height);
      time++;

      // Draw background fog/mist
      mists.forEach(m => {
        m.update();
        m.draw(ctx, currentDarkness > 0.5);
      });

      // Draw Mountains (Back to Front)
      layers.forEach(l => l.draw(ctx, currentDarkness));

      animationFrameId = requestAnimationFrame(animate);
    };

    window.addEventListener('resize', resize);
    resize();
    animate();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      className={`fixed inset-0 w-full h-full pointer-events-none z-0 transition-opacity duration-1000 ${darkMode ? 'opacity-90 mix-blend-multiply' : 'opacity-80 mix-blend-multiply'}`}
    />
  );
};

export default InkCanvas;

