                        >
                            没有备份
                        </a>
                    )}
                </div>
              ))}
            </div>
          )}

        </div>

        {/* Page Bottom Notes */}
        <div className="mt-12 w-full text-center space-y-6">
            <div className={`text-sm leading-relaxed max-w-2xl mx-auto p-4 transition-colors duration-[1500ms] ${isSecretOpen ? 'text-gray-500' : 'text-ink-700'}`}>
               <p className="mb-2">
                 EE3 邀请码：<span className="text-indigo-stone select-all font-bold cursor-text">mpgh</span> &nbsp;|&nbsp; 
                 备份网址：<a href="https://www.bxkp.org" target="_blank" className="text-indigo-stone hover:text-cinnabar border-b border-transparent hover:border-cinnabar transition-all">3w</a>、
                 <a href="https://v.bxkp.org" target="_blank" className="text-indigo-stone hover:text-cinnabar border-b border-transparent hover:border-cinnabar transition-all">Vercel</a>
               </p>
               <p>
